import{_ as t,o as e,c as n,S as s}from"./chunks/framework.C6RQlTYc.js";const h=JSON.parse('{"title":"面试官问：Transformer 架构为什么是革命性的？相比 RNN 有什么优势？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_6-transformer.md","filePath":"面试官问/17ai/q_ai_6-transformer.md","lastUpdated":1778207238000}'),r={name:"面试官问/17ai/q_ai_6-transformer.md"};function o(i,a,l,p,d,c){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="面试官问-transformer-架构为什么是革命性的-相比-rnn-有什么优势" tabindex="-1">面试官问：Transformer 架构为什么是革命性的？相比 RNN 有什么优势？ <a class="header-anchor" href="#面试官问-transformer-架构为什么是革命性的-相比-rnn-有什么优势" aria-label="Permalink to &quot;面试官问：Transformer 架构为什么是革命性的？相比 RNN 有什么优势？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_7-transformer.html">Transformer 架构</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_10-attention.html">Attention 注意力机制</a></p></blockquote><p><strong>考察点</strong>：Self-Attention 机制的核心原理、与 RNN/LSTM 的对比优势、Encoder-Decoder 结构理解</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p>Transformer 是 2017 年 Google 提出的架构，革命性在于<strong>自注意力（Self-Attention）机制 + 并行计算</strong>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>Transformer 结构：</span></span>
<span class="line"><span>├── Encoder（编码器）：理解输入文本</span></span>
<span class="line"><span>│   ├── Self-Attention：每个词关注整个句子的所有词</span></span>
<span class="line"><span>│   └── Feed Forward：非线性变换</span></span>
<span class="line"><span>└── Decoder（解码器）：生成输出文本</span></span>
<span class="line"><span>    ├── Masked Self-Attention：只看左边的词（防止偷看答案）</span></span>
<span class="line"><span>    ├── Cross-Attention：关注 Encoder 输出</span></span>
<span class="line"><span>    └── Feed Forward</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><table><thead><tr><th>对比</th><th>RNN/LSTM</th><th>Transformer</th></tr></thead><tbody><tr><td><strong>计算方式</strong></td><td>串行（step by step）</td><td>并行（矩阵乘法）</td></tr><tr><td><strong>长距离依赖</strong></td><td>容易遗忘</td><td>Attention 直接关联</td></tr><tr><td><strong>训练速度</strong></td><td>慢（不可并行）</td><td>快（GPU 友好）</td></tr><tr><td><strong>梯度问题</strong></td><td>梯度消失/爆炸</td><td>残差连接缓解</td></tr></tbody></table><p><strong>核心公式</strong>：<code>Attention(Q, K, V) = softmax(QK^T / √d_k) × V</code></p><ul><li>Q (Query)：我在找什么？</li><li>K (Key)：我能提供什么？</li><li>V (Value)：我实际的内容是什么？</li></ul><p><strong>为什么重要</strong>：NLP 领域所有重大进展（BERT、GPT、T5、LLaMA）都基于 Transformer。可以说&quot;Attention Is All You Need&quot;这篇论文开启了 LLM 时代。</p><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>说出 Transformer 的两大组件：Encoder 和 Decoder</li><li>解释 Self-Attention 的核心：让每个词能直接&quot;看到&quot;所有其他词</li><li>对比 RNN 的串行瓶颈</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_7-transformer.html">Transformer 架构概念讲解</a></p></blockquote>`,5)])])}const u=t(r,[["render",o]]);export{h as __pageData,u as default};
